+fn contains_shell_command_substitution(s: &str) -> bool {
+    let mut in_single = false;
+    let mut in_double = false;
+    let mut escaped = false;
+
+    let mut chars = s.chars().peekable();
+    while let Some(c) = chars.next() {
+        if escaped {
+            escaped = false;
+            continue;
+        }
+
+        if c == '\\' && !in_single {
+            escaped = true;
+            continue;
+        }
+
+        match c {
+            '\'' if !in_double => {
+                in_single = !in_single;
+            }
+            '"' if !in_single => {
+                in_double = !in_double;
+            }
+            '`' if !in_single => {
+                return true;
+            }
+            '$' if !in_single => {
+                if chars.peek().copied() == Some('(') {
+                    return true;
+                }
+            }
+            _ => {}
+        }
+    }
+
+    false
+}
